import{_ as t,o as a,c as r,ai as e}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"AI & 机器学习项目","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/ai-projects.md","filePath":"open-source/ai-projects.md"}'),i={name:"open-source/ai-projects.md"};function o(n,l,h,s,u,g){return a(),r("div",null,[...l[0]||(l[0]=[e('<h1 id="ai-机器学习项目" tabindex="-1">AI &amp; 机器学习项目 <a class="header-anchor" href="#ai-机器学习项目" aria-label="Permalink to “AI &amp; 机器学习项目”">​</a></h1><p>本页面精选了AI、机器学习、深度学习相关的开源项目，包括框架、工具库、应用等。</p><h2 id="深度学习框架" tabindex="-1">深度学习框架 <a class="header-anchor" href="#深度学习框架" aria-label="Permalink to “深度学习框架”">​</a></h2><h3 id="tensorflow-生态" tabindex="-1">TensorFlow 生态 <a class="header-anchor" href="#tensorflow-生态" aria-label="Permalink to “TensorFlow 生态”">​</a></h3><ul><li><p><strong>TensorFlow</strong>：Google开源机器学习框架</p><ul><li>GitHub: <a href="https://github.com/tensorflow/tensorflow" target="_blank" rel="noreferrer">https://github.com/tensorflow/tensorflow</a></li><li>特点: 生产级、分布式训练、多种语言支持</li><li>适用: 研究和生产环境</li></ul></li><li><p><strong>TensorFlow.js</strong>：浏览器中运行的TensorFlow</p><ul><li>GitHub: <a href="https://github.com/tensorflow/tfjs" target="_blank" rel="noreferrer">https://github.com/tensorflow/tfjs</a></li><li>功能: 浏览器ML、Node.js支持</li></ul></li><li><p><strong>TensorFlow Serving</strong>：模型服务系统</p><ul><li>GitHub: <a href="https://github.com/tensorflow/serving" target="_blank" rel="noreferrer">https://github.com/tensorflow/serving</a></li><li>功能: 模型部署、高性能推理</li></ul></li></ul><h3 id="pytorch-生态" tabindex="-1">PyTorch 生态 <a class="header-anchor" href="#pytorch-生态" aria-label="Permalink to “PyTorch 生态”">​</a></h3><ul><li><p><strong>PyTorch</strong>：Facebook开源深度学习框架</p><ul><li>GitHub: <a href="https://github.com/pytorch/pytorch" target="_blank" rel="noreferrer">https://github.com/pytorch/pytorch</a></li><li>特点: 动态图、易用性好、研究友好</li><li>适用: 学术研究、快速原型</li></ul></li><li><p><strong>PyTorch Lightning</strong>：PyTorch轻量级包装</p><ul><li>GitHub: <a href="https://github.com/PyTorchLightning/pytorch-lightning" target="_blank" rel="noreferrer">https://github.com/PyTorchLightning/pytorch-lightning</a></li><li>功能: 简化训练、自动优化</li></ul></li><li><p><strong>TorchServe</strong>：PyTorch模型服务</p><ul><li>GitHub: <a href="https://github.com/pytorch/serve" target="_blank" rel="noreferrer">https://github.com/pytorch/serve</a></li><li>功能: 模型部署、A/B测试</li></ul></li></ul><h3 id="其他框架" tabindex="-1">其他框架 <a class="header-anchor" href="#其他框架" aria-label="Permalink to “其他框架”">​</a></h3><ul><li><p><strong>JAX</strong>：Google的数值计算库</p><ul><li>GitHub: <a href="https://github.com/google/jax" target="_blank" rel="noreferrer">https://github.com/google/jax</a></li><li>特点: 可组合变换、自动微分</li></ul></li><li><p><strong>MXNet</strong>：Apache深度学习框架</p><ul><li>GitHub: <a href="https://github.com/apache/mxnet" target="_blank" rel="noreferrer">https://github.com/apache/mxnet</a></li><li>特点: 高效、灵活、可扩展</li></ul></li></ul><h2 id="机器学习库" tabindex="-1">机器学习库 <a class="header-anchor" href="#机器学习库" aria-label="Permalink to “机器学习库”">​</a></h2><h3 id="经典ml库" tabindex="-1">经典ML库 <a class="header-anchor" href="#经典ml库" aria-label="Permalink to “经典ML库”">​</a></h3><ul><li><p><strong>scikit-learn</strong>：Python机器学习库</p><ul><li>GitHub: <a href="https://github.com/scikit-learn/scikit-learn" target="_blank" rel="noreferrer">https://github.com/scikit-learn/scikit-learn</a></li><li>功能: 分类、回归、聚类、降维</li><li>特点: 简单易用、完整文档</li></ul></li><li><p><strong>XGBoost</strong>：梯度提升树库</p><ul><li>GitHub: <a href="https://github.com/dmlc/xgboost" target="_blank" rel="noreferrer">https://github.com/dmlc/xgboost</a></li><li>特点: 高性能、分布式训练</li></ul></li><li><p><strong>LightGBM</strong>：微软梯度提升框架</p><ul><li>GitHub: <a href="https://github.com/microsoft/LightGBM" target="_blank" rel="noreferrer">https://github.com/microsoft/LightGBM</a></li><li>特点: 快速、内存效率高</li></ul></li><li><p><strong>CatBoost</strong>：Yandex梯度提升库</p><ul><li>GitHub: <a href="https://github.com/catboost/catboost" target="_blank" rel="noreferrer">https://github.com/catboost/catboost</a></li><li>特点: 类别特征处理、GPU支持</li></ul></li></ul><h3 id="统计与数学" tabindex="-1">统计与数学 <a class="header-anchor" href="#统计与数学" aria-label="Permalink to “统计与数学”">​</a></h3><ul><li><p><strong>NumPy</strong>：数值计算库</p><ul><li>GitHub: <a href="https://github.com/numpy/numpy" target="_blank" rel="noreferrer">https://github.com/numpy/numpy</a></li><li>功能: 多维数组、数学函数</li></ul></li><li><p><strong>SciPy</strong>：科学计算库</p><ul><li>GitHub: <a href="https://github.com/scipy/scipy" target="_blank" rel="noreferrer">https://github.com/scipy/scipy</a></li><li>功能: 优化、积分、信号处理</li></ul></li><li><p><strong>Pandas</strong>：数据分析库</p><ul><li>GitHub: <a href="https://github.com/pandas-dev/pandas" target="_blank" rel="noreferrer">https://github.com/pandas-dev/pandas</a></li><li>功能: 数据操作、时间序列</li></ul></li></ul><h2 id="数据科学工具" tabindex="-1">数据科学工具 <a class="header-anchor" href="#数据科学工具" aria-label="Permalink to “数据科学工具”">​</a></h2><h3 id="可视化" tabindex="-1">可视化 <a class="header-anchor" href="#可视化" aria-label="Permalink to “可视化”">​</a></h3><ul><li><p><strong>Matplotlib</strong>：Python绘图库</p><ul><li>GitHub: <a href="https://github.com/matplotlib/matplotlib" target="_blank" rel="noreferrer">https://github.com/matplotlib/matplotlib</a></li><li>功能: 2D/3D绘图、统计图表</li></ul></li><li><p><strong>Seaborn</strong>：统计数据可视化</p><ul><li>GitHub: <a href="https://github.com/mwaskom/seaborn" target="_blank" rel="noreferrer">https://github.com/mwaskom/seaborn</a></li><li>功能: 基于matplotlib、美观样式</li></ul></li><li><p><strong>Plotly</strong>：交互式图表</p><ul><li>GitHub: <a href="https://github.com/plotly/plotly.py" target="_blank" rel="noreferrer">https://github.com/plotly/plotly.py</a></li><li>功能: Web交互图表、仪表板</li></ul></li></ul><h3 id="数据处理" tabindex="-1">数据处理 <a class="header-anchor" href="#数据处理" aria-label="Permalink to “数据处理”">​</a></h3><ul><li><p><strong>Dask</strong>：并行计算库</p><ul><li>GitHub: <a href="https://github.com/dask/dask" target="_blank" rel="noreferrer">https://github.com/dask/dask</a></li><li>功能: 大数据处理、并行计算</li></ul></li><li><p><strong>Polars</strong>：快速DataFrame库</p><ul><li>GitHub: <a href="https://github.com/pola-rs/polars" target="_blank" rel="noreferrer">https://github.com/pola-rs/polars</a></li><li>特点: Rust性能、Python接口</li></ul></li></ul><h2 id="计算机视觉" tabindex="-1">计算机视觉 <a class="header-anchor" href="#计算机视觉" aria-label="Permalink to “计算机视觉”">​</a></h2><h3 id="opencv-生态" tabindex="-1">OpenCV 生态 <a class="header-anchor" href="#opencv-生态" aria-label="Permalink to “OpenCV 生态”">​</a></h3><ul><li><p><strong>OpenCV</strong>：计算机视觉库</p><ul><li>GitHub: <a href="https://github.com/opencv/opencv" target="_blank" rel="noreferrer">https://github.com/opencv/opencv</a></li><li>功能: 图像处理、视频分析</li></ul></li><li><p><strong>OpenCV.js</strong>：JavaScript版本</p><ul><li>GitHub: <a href="https://github.com/opencv/opencv" target="_blank" rel="noreferrer">https://github.com/opencv/opencv</a></li><li>功能: 浏览器计算机视觉</li></ul></li></ul><h3 id="深度学习视觉" tabindex="-1">深度学习视觉 <a class="header-anchor" href="#深度学习视觉" aria-label="Permalink to “深度学习视觉”">​</a></h3><ul><li><p><strong>Detectron2</strong>：Facebook目标检测框架</p><ul><li>GitHub: <a href="https://github.com/facebookresearch/detectron2" target="_blank" rel="noreferrer">https://github.com/facebookresearch/detectron2</a></li><li>功能: 目标检测、实例分割</li></ul></li><li><p><strong>MMDetection</strong>：开源目标检测工具箱</p><ul><li>GitHub: <a href="https://github.com/open-mmlab/mmdetection" target="_blank" rel="noreferrer">https://github.com/open-mmlab/mmdetection</a></li><li>功能: 多种检测算法</li></ul></li><li><p><strong>YOLOv5</strong>：实时目标检测</p><ul><li>GitHub: <a href="https://github.com/ultralytics/yolov5" target="_blank" rel="noreferrer">https://github.com/ultralytics/yolov5</a></li><li>特点: 快速、准确、易部署</li></ul></li></ul><h2 id="自然语言处理" tabindex="-1">自然语言处理 <a class="header-anchor" href="#自然语言处理" aria-label="Permalink to “自然语言处理”">​</a></h2><h3 id="核心库" tabindex="-1">核心库 <a class="header-anchor" href="#核心库" aria-label="Permalink to “核心库”">​</a></h3><ul><li><p><strong>NLTK</strong>：自然语言处理工具包</p><ul><li>GitHub: <a href="https://github.com/nltk/nltk" target="_blank" rel="noreferrer">https://github.com/nltk/nltk</a></li><li>功能: 文本处理、语言分析</li></ul></li><li><p><strong>spaCy</strong>：工业级NLP库</p><ul><li>GitHub: <a href="https://github.com/explosion/spaCy" target="_blank" rel="noreferrer">https://github.com/explosion/spaCy</a></li><li>特点: 快速、准确、易用</li></ul></li><li><p><strong>Transformers</strong>：Hugging Face模型库</p><ul><li>GitHub: <a href="https://github.com/huggingface/transformers" target="_blank" rel="noreferrer">https://github.com/huggingface/transformers</a></li><li>功能: 预训练模型、多种任务</li></ul></li></ul><h3 id="中文nlp" tabindex="-1">中文NLP <a class="header-anchor" href="#中文nlp" aria-label="Permalink to “中文NLP”">​</a></h3><ul><li><p><strong>jieba</strong>：中文分词库</p><ul><li>GitHub: <a href="https://github.com/fxsjy/jieba" target="_blank" rel="noreferrer">https://github.com/fxsjy/jieba</a></li><li>功能: 中文分词、关键词提取</li></ul></li><li><p><strong>HanLP</strong>：多语言NLP库</p><ul><li>GitHub: <a href="https://github.com/hankcs/HanLP" target="_blank" rel="noreferrer">https://github.com/hankcs/HanLP</a></li><li>功能: 中文处理、多语言支持</li></ul></li></ul><h2 id="大语言模型" tabindex="-1">大语言模型 <a class="header-anchor" href="#大语言模型" aria-label="Permalink to “大语言模型”">​</a></h2><h3 id="开源llm" tabindex="-1">开源LLM <a class="header-anchor" href="#开源llm" aria-label="Permalink to “开源LLM”">​</a></h3><ul><li><p><strong>Llama</strong>：Meta大语言模型</p><ul><li>GitHub: <a href="https://github.com/facebookresearch/llama" target="_blank" rel="noreferrer">https://github.com/facebookresearch/llama</a></li><li>特点: 开源、指令微调</li></ul></li><li><p><strong>GPT-J</strong>：开源GPT模型</p><ul><li>GitHub: <a href="https://github.com/kingoflolz/mesh-transformer-jax" target="_blank" rel="noreferrer">https://github.com/kingoflolz/mesh-transformer-jax</a></li><li>功能: 文本生成、对话</li></ul></li><li><p><strong>BLOOM</strong>：多语言大模型</p><ul><li>GitHub: <a href="https://github.com/bigscience-workshop/bloom" target="_blank" rel="noreferrer">https://github.com/bigscience-workshop/bloom</a></li><li>特点: 176种语言支持</li></ul></li></ul><h3 id="模型平台" tabindex="-1">模型平台 <a class="header-anchor" href="#模型平台" aria-label="Permalink to “模型平台”">​</a></h3><ul><li><p><strong>Hugging Face</strong>：模型分享平台</p><ul><li>GitHub: <a href="https://github.com/huggingface/huggingface_hub" target="_blank" rel="noreferrer">https://github.com/huggingface/huggingface_hub</a></li><li>功能: 模型下载、上传、分享</li></ul></li><li><p><strong>ModelScope</strong>：阿里模型平台</p><ul><li>GitHub: <a href="https://github.com/modelscope/modelscope" target="_blank" rel="noreferrer">https://github.com/modelscope/modelscope</a></li><li>功能: 中文模型、工具链</li></ul></li></ul><h2 id="ai应用框架" tabindex="-1">AI应用框架 <a class="header-anchor" href="#ai应用框架" aria-label="Permalink to “AI应用框架”">​</a></h2><h3 id="langchain" tabindex="-1">LangChain <a class="header-anchor" href="#langchain" aria-label="Permalink to “LangChain”">​</a></h3><ul><li><p><strong>LangChain</strong>：LLM应用开发框架</p><ul><li>GitHub: <a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></li><li>功能: 链式调用、记忆管理、代理</li></ul></li><li><p><strong>LangChain.js</strong>：JavaScript版本</p><ul><li>GitHub: <a href="https://github.com/langchain-ai/langchainjs" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchainjs</a></li><li>功能: Node.js LLM应用</li></ul></li></ul><h3 id="llamaindex" tabindex="-1">LlamaIndex <a class="header-anchor" href="#llamaindex" aria-label="Permalink to “LlamaIndex”">​</a></h3><ul><li><strong>LlamaIndex</strong>：LLM数据框架 <ul><li>GitHub: <a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></li><li>功能: 数据索引、检索增强</li></ul></li></ul><h3 id="autogen" tabindex="-1">AutoGen <a class="header-anchor" href="#autogen" aria-label="Permalink to “AutoGen”">​</a></h3><ul><li><strong>AutoGen</strong>：多代理对话框架 <ul><li>GitHub: <a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a></li><li>功能: 代理对话、任务解决</li></ul></li></ul><h2 id="mlops-工具" tabindex="-1">MLOps 工具 <a class="header-anchor" href="#mlops-工具" aria-label="Permalink to “MLOps 工具”">​</a></h2><h3 id="模型管理" tabindex="-1">模型管理 <a class="header-anchor" href="#模型管理" aria-label="Permalink to “模型管理”">​</a></h3><ul><li><p><strong>MLflow</strong>：机器学习生命周期管理</p><ul><li>GitHub: <a href="https://github.com/mlflow/mlflow" target="_blank" rel="noreferrer">https://github.com/mlflow/mlflow</a></li><li>功能: 实验跟踪、模型注册</li></ul></li><li><p><strong>DVC</strong>：数据版本控制</p><ul><li>GitHub: <a href="https://github.com/iterative/dvc" target="_blank" rel="noreferrer">https://github.com/iterative/dvc</a></li><li>功能: 数据版本化、管道管理</li></ul></li></ul><h3 id="模型部署" tabindex="-1">模型部署 <a class="header-anchor" href="#模型部署" aria-label="Permalink to “模型部署”">​</a></h3><ul><li><p><strong>BentoML</strong>：ML模型服务框架</p><ul><li>GitHub: <a href="https://github.com/bentoml/BentoML" target="_blank" rel="noreferrer">https://github.com/bentoml/BentoML</a></li><li>功能: 模型打包、API服务</li></ul></li><li><p><strong>Cortex</strong>：云原生模型服务</p><ul><li>GitHub: <a href="https://github.com/cortexlabs/cortex" target="_blank" rel="noreferrer">https://github.com/cortexlabs/cortex</a></li><li>功能: 自动扩展、A/B测试</li></ul></li></ul><h2 id="强化学习" tabindex="-1">强化学习 <a class="header-anchor" href="#强化学习" aria-label="Permalink to “强化学习”">​</a></h2><ul><li><p><strong>Stable Baselines3</strong>：强化学习算法库</p><ul><li>GitHub: <a href="https://github.com/DLR-RM/stable-baselines3" target="_blank" rel="noreferrer">https://github.com/DLR-RM/stable-baselines3</a></li><li>功能: 经典RL算法实现</li></ul></li><li><p><strong>Ray RLlib</strong>：分布式强化学习</p><ul><li>GitHub: <a href="https://github.com/ray-project/ray" target="_blank" rel="noreferrer">https://github.com/ray-project/ray</a></li><li>功能: 扩展RL算法</li></ul></li></ul><h2 id="自动机器学习" tabindex="-1">自动机器学习 <a class="header-anchor" href="#自动机器学习" aria-label="Permalink to “自动机器学习”">​</a></h2><ul><li><p><strong>Auto-sklearn</strong>：自动化机器学习</p><ul><li>GitHub: <a href="https://github.com/automl/auto-sklearn" target="_blank" rel="noreferrer">https://github.com/automl/auto-sklearn</a></li><li>功能: 自动模型选择、超参数调优</li></ul></li><li><p><strong>TPOT</strong>：基于遗传编程的AutoML</p><ul><li>GitHub: <a href="https://github.com/EpistasisLab/tpot" target="_blank" rel="noreferrer">https://github.com/EpistasisLab/tpot</a></li><li>功能: 管道优化、特征选择</li></ul></li></ul><h2 id="java-ai项目" tabindex="-1">Java AI项目 <a class="header-anchor" href="#java-ai项目" aria-label="Permalink to “Java AI项目”">​</a></h2><h3 id="深度学习" tabindex="-1">深度学习 <a class="header-anchor" href="#深度学习" aria-label="Permalink to “深度学习”">​</a></h3><ul><li><p><strong>Deeplearning4j</strong>：JVM深度学习库</p><ul><li>GitHub: <a href="https://github.com/deeplearning4j/deeplearning4j" target="_blank" rel="noreferrer">https://github.com/deeplearning4j/deeplearning4j</a></li><li>特点: Java/Scala支持、分布式</li></ul></li><li><p><strong>DL4J</strong>：Deeplearning4j示例</p><ul><li>GitHub: <a href="https://github.com/deeplearning4j/dl4j-examples" target="_blank" rel="noreferrer">https://github.com/deeplearning4j/dl4j-examples</a></li><li>功能: 完整示例、教程</li></ul></li></ul><h3 id="机器学习" tabindex="-1">机器学习 <a class="header-anchor" href="#机器学习" aria-label="Permalink to “机器学习”">​</a></h3><ul><li><p><strong>Smile</strong>：统计机器学习库</p><ul><li>GitHub: <a href="https://github.com/haifengl/smile" target="_blank" rel="noreferrer">https://github.com/haifengl/smile</a></li><li>功能: 分类、回归、聚类</li></ul></li><li><p><strong>Tribuo</strong>：Oracle机器学习库</p><ul><li>GitHub: <a href="https://github.com/oracle/tribuo" target="_blank" rel="noreferrer">https://github.com/oracle/tribuo</a></li><li>功能: 多模型支持、解释性</li></ul></li></ul><h2 id="ai工具与平台" tabindex="-1">AI工具与平台 <a class="header-anchor" href="#ai工具与平台" aria-label="Permalink to “AI工具与平台”">​</a></h2><h3 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h3><ul><li><p><strong>Jupyter</strong>：交互式计算环境</p><ul><li>GitHub: <a href="https://github.com/jupyter/jupyter" target="_blank" rel="noreferrer">https://github.com/jupyter/jupyter</a></li><li>功能: 笔记本、数据分析</li></ul></li><li><p><strong>Colab</strong>：Google云端Jupyter</p><ul><li>GitHub: <a href="https://github.com/googlecolab/colabtools" target="_blank" rel="noreferrer">https://github.com/googlecolab/colabtools</a></li><li>功能: 免费GPU、云端开发</li></ul></li></ul><h3 id="数据标注" tabindex="-1">数据标注 <a class="header-anchor" href="#数据标注" aria-label="Permalink to “数据标注”">​</a></h3><ul><li><p><strong>Label Studio</strong>：数据标注平台</p><ul><li>GitHub: <a href="https://github.com/heartexlabs/label-studio" target="_blank" rel="noreferrer">https://github.com/heartexlabs/label-studio</a></li><li>功能: 多格式标注、团队协作</li></ul></li><li><p><strong>CVAT</strong>：计算机视觉标注工具</p><ul><li>GitHub: <a href="https://github.com/opencv/cvat" target="_blank" rel="noreferrer">https://github.com/opencv/cvat</a></li><li>功能: 视频标注、图像标注</li></ul></li></ul>',60)])])}const c=t(i,[["render",o]]);export{p as __pageData,c as default};
